async (page) => {
  // Set attack style to Hack (index 0) for Strength XP
  await page.evaluate(() => window.game.player.setAttackStyle(0));
  await page.waitForTimeout(500);

  // Equip bronze axe from slot 0
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(800);
  await page.evaluate((idx) => {
    const slots = document.querySelectorAll('.item-slot');
    if (slots[idx]) slots[idx].click();
  }, 0);
  await page.waitForTimeout(800);
  await page.evaluate(() => {
    const btn = document.querySelector('.action-equip');
    if (btn) btn.click();
  });
  await page.waitForTimeout(500);
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(500);

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      pos: gs.player_position,
      stats: gs.player_stats,
      skills: gs.skills,
      inventory: gs.inventory,
      nearby: gs.nearby_entities.slice(0, 10).map(e => ({name: e.name, type: e.type, dist: e.distance, x: e.x, y: e.y, cx: e.click_x, cy: e.click_y, on_screen: e.on_screen, quest_npc: e.quest_npc}))
    });
  });
  return state;
}
